//! H.264 intra prediction (Intra_4x4 + Intra_16x16) + reconstruction over the
//! integer transform/quant primitives in `crate::h264_transform`.
//!
//! Pure Rust, std+alloc only, no external crates, no threads — wasm32-safe.
//!
//! References:
//!   ITU-T H.264 (04/2017) §8.3.1 (Intra_4x4), §8.3.3 (Intra_16x16)

use crate::h264_transform::{dequant4x4, fdct4x4, idct4x4, quant4x4};

// ─────────────────────────────────────────────────────────────────────────────
// Intra_4x4 luma prediction  (H.264 §8.3.1)
// ─────────────────────────────────────────────────────────────────────────────
//
// Prediction modes (§8.3.1.1):
//   0  Vertical          — copies the 4 top samples down all rows
//   1  Horizontal        — copies the 4 left samples across all columns
//   2  DC                — average of available top/left neighbors (else 128)
//   3  Diagonal-Down-Left — diagonal extrapolation using top + top-right
//   4  Diagonal-Down-Right— diagonal extrapolation using top-left, top, left
//
// `top` is 8 wide so mode 3 can reach the top-right samples.  When
// `!have_top_right` the caller should replicate top[3] into top[4..8].
//
// The returned block is 4×4 row-major (16 bytes).

/// Intra_4x4 luma prediction.
///
/// * `mode`         — prediction mode (0..=8; unknown modes fall back to DC)
/// * `left`         — 4 left-column samples [p[-1,0]..p[-1,3]], top-to-bottom
/// * `top`          — 8 above-row samples [p[0,-1]..p[7,-1]], left-to-right
///                    (`top[0..4]` are the direct above-block samples;
///                     `top[4..8]` are the above-right samples for modes 3/7)
/// * `top_left`     — the above-left corner sample p[-1,-1]
/// * `have_left`    — left samples are available
/// * `have_top`     — top samples are available
/// * `have_top_right` — top-right samples are available (if false, replicate top[3])
pub fn intra4x4_predict(
    mode: u8,
    left: &[u8; 4],
    top: &[u8; 8],
    top_left: u8,
    have_left: bool,
    have_top: bool,
    have_top_right: bool,
) -> [u8; 16] {
    // Build an extended top array: positions 0..4 = direct top, 4..8 = top-right
    // (replicate top[3] when above-right is unavailable — §8.3.1.2.3 note).
    let mut t = [0u8; 8];
    if have_top {
        t[0..4].copy_from_slice(&top[0..4]);
        if have_top_right {
            t[4..8].copy_from_slice(&top[4..8]);
        } else {
            let last = top[3];
            for v in &mut t[4..8] {
                *v = last;
            }
        }
    }

    match mode {
        // ── Mode 0: Vertical ─────────────────────────────────────────────────
        0 if have_top => {
            let mut blk = [0u8; 16];
            for row in 0..4 {
                blk[row * 4..row * 4 + 4].copy_from_slice(&t[0..4]);
            }
            blk
        }

        // ── Mode 1: Horizontal ───────────────────────────────────────────────
        1 if have_left => {
            let mut blk = [0u8; 16];
            for row in 0..4 {
                let s = left[row];
                for col in 0..4 {
                    blk[row * 4 + col] = s;
                }
            }
            blk
        }

        // ── Mode 2: DC ───────────────────────────────────────────────────────
        // §8.3.1.2.3: average whichever neighbors are available; else 128.
        2 => {
            let dc = dc4_value(
                if have_left { Some(left) } else { None },
                if have_top { Some(&t) } else { None },
            );
            [dc; 16]
        }

        // ── Mode 3: Diagonal-Down-Left ───────────────────────────────────────
        // §8.3.1.2.4: uses top[0..7] (requires have_top)
        3 if have_top => diag_down_left_4x4(&t),

        // ── Mode 4: Diagonal-Down-Right ──────────────────────────────────────
        // §8.3.1.2.5: uses top-left, top[0..3], left[0..3]
        4 if have_top && have_left => diag_down_right_4x4(&t, left, top_left),

        // ── Mode 5: Vertical-Right ───────────────────────────────────────────
        // §8.3.1.2.6: uses top-left, top[0..3], left[0..3]
        5 if have_top && have_left => vert_right_4x4(&t, left, top_left),

        // ── Mode 6: Horizontal-Down ──────────────────────────────────────────
        // §8.3.1.2.7: uses top-left, top[0..3], left[0..3]
        6 if have_top && have_left => horiz_down_4x4(&t, left, top_left),

        // ── Mode 7: Vertical-Left ────────────────────────────────────────────
        // §8.3.1.2.8: uses top[0..7] (requires have_top; above-right clamp
        //             already applied in `t` above)
        7 if have_top => vert_left_4x4(&t),

        // ── Mode 8: Horizontal-Up ────────────────────────────────────────────
        // §8.3.1.2.9: uses left[0..3] only
        8 if have_left => horiz_up_4x4(left),

        // Fallback to DC for any unavailable mode (including modes 3-8 without
        // the required neighbors, and any unrecognised mode value)
        _ => {
            let dc = dc4_value(
                if have_left { Some(left) } else { None },
                if have_top { Some(&t) } else { None },
            );
            [dc; 16]
        }
    }
}

/// DC value for Intra_4x4: average of available top/left (else 128).
fn dc4_value(left: Option<&[u8; 4]>, top: Option<&[u8; 8]>) -> u8 {
    match (left, top) {
        (Some(l), Some(t)) => {
            let sum: i32 = l.iter().map(|&x| x as i32).sum::<i32>()
                + t[0..4].iter().map(|&x| x as i32).sum::<i32>();
            ((sum + 4) >> 3) as u8 // (sum + 4) / 8
        }
        (Some(l), None) => {
            let sum: i32 = l.iter().map(|&x| x as i32).sum();
            ((sum + 2) >> 2) as u8 // (sum + 2) / 4
        }
        (None, Some(t)) => {
            let sum: i32 = t[0..4].iter().map(|&x| x as i32).sum();
            ((sum + 2) >> 2) as u8
        }
        (None, None) => 128,
    }
}

/// Mode 3 Diagonal-Down-Left 4×4 (§8.3.1.2.4).
///
/// p[x,y] = filter(t[x+y], t[x+y+1], t[x+y+2])
/// where filter(a,b,c) = (a + 2b + c + 2) >> 2
/// Special case at (3,3): (t[6] + 3*t[7] + 2) >> 2
fn diag_down_left_4x4(t: &[u8; 8]) -> [u8; 16] {
    // Pre-compute the 7 filter taps needed (indices 0..7 → taps 0..6)
    // tap[i] = (t[i] + 2*t[i+1] + t[i+2] + 2) >> 2  for i = 0..5
    // tap[6] = (t[6] + 3*t[7] + 2) >> 2              (boundary clamp)
    let filter = |a: u8, b: u8, c: u8| -> u8 {
        ((a as i32 + 2 * b as i32 + c as i32 + 2) >> 2) as u8
    };
    let taps: [u8; 7] = [
        filter(t[0], t[1], t[2]),
        filter(t[1], t[2], t[3]),
        filter(t[2], t[3], t[4]),
        filter(t[3], t[4], t[5]),
        filter(t[4], t[5], t[6]),
        filter(t[5], t[6], t[7]),
        // boundary: last position clamps to t[7]
        ((t[6] as i32 + 3 * t[7] as i32 + 2) >> 2) as u8,
    ];

    let mut blk = [0u8; 16];
    for y in 0..4usize {
        for x in 0..4usize {
            let idx = x + y;
            blk[y * 4 + x] = if idx < 6 { taps[idx] } else { taps[6] };
        }
    }
    blk
}

/// Mode 4 Diagonal-Down-Right 4×4 (§8.3.1.2.5).
///
/// Two regions separated by the main diagonal (x == y):
///   x > y : uses top/top-left samples
///   x < y : uses left/top-left samples
///   x == y: top-left sample
fn diag_down_right_4x4(t: &[u8; 8], l: &[u8; 4], tl: u8) -> [u8; 16] {
    // Build a combined reference array a[-3..-1] = l[2..0], a[0]=tl, a[1..4]=t[0..3]
    // Using index offset: ref[0]=l[3], ref[1]=l[2], ref[2]=l[1], ref[3]=l[0],
    //                     ref[4]=tl,   ref[5]=t[0], ref[6]=t[1], ref[7]=t[2], ref[8]=t[3]
    let r: [u8; 9] = [l[3], l[2], l[1], l[0], tl, t[0], t[1], t[2], t[3]];

    let filter = |a: u8, b: u8, c: u8| -> u8 {
        ((a as i32 + 2 * b as i32 + c as i32 + 2) >> 2) as u8
    };

    let mut blk = [0u8; 16];
    for y in 0..4usize {
        for x in 0..4usize {
            // In the reference array, position (x,y) maps to index 4 + x - y
            let idx = (4 + x) as i32 - y as i32;
            // clamp to valid range [0..8] — boundary cases use the edge value
            let i = idx.clamp(0, 8) as usize;
            let a = if i == 0 { r[0] } else { r[i - 1] };
            let b = r[i];
            let c = if i + 1 < 9 { r[i + 1] } else { r[8] };
            blk[y * 4 + x] = filter(a, b, c);
        }
    }
    blk
}

/// Mode 5 Vertical-Right 4×4 (§8.3.1.2.6).
///
/// Uses top-left sample (`tl`), top samples `t[0..4]` (p[0,-1]..p[3,-1]),
/// and left samples `l[0..4]` (p[-1,0]..p[-1,3]).
///
/// Let zVR = 2*x - y.
///   zVR even ≥ 0 (0,2,4,6):  pred = (p[x-(y>>1)-1, -1] + p[x-(y>>1), -1] + 1) >> 1
///   zVR odd  > 0 (1,3,5,7):  pred = (p[x-(y>>1)-2, -1] + 2*p[x-(y>>1)-1, -1] + p[x-(y>>1), -1] + 2) >> 2
///   zVR == -1:                pred = (p[-1,0] + 2*p[-1,-1] + p[0,-1] + 2) >> 2
///   zVR < -1 (i.e. -2,-3):   pred = (p[-1,y-1] + 2*p[-1,y-2] + p[-1,y-3] + 2) >> 2
///                              (where p[-1,-1]=tl, p[-1,-2] clamps to p[-1,0])
///
/// The p[x',-1] reference is indexed into the combined top array
/// `ref_top[0]=tl, ref_top[1..5]=t[0..4]` so p[k,-1] = ref_top[k+1], tl = ref_top[0].
fn vert_right_4x4(t: &[u8; 8], l: &[u8; 4], tl: u8) -> [u8; 16] {
    // ref_top[k] = p[k-1, -1]:  ref_top[0]=tl, ref_top[1]=t[0], ..., ref_top[4]=t[3]
    // Indexing: p[k, -1] = ref_top[k + 1]  (k in -1..3)
    //           p[-1, -1] = tl = ref_top[0]
    let ref_top: [u8; 5] = [tl, t[0], t[1], t[2], t[3]];
    // ref_top access for p[k,-1]: index = k+1, must be in 0..5
    // p[k,-1] where k ∈ {-1,0,1,2,3} → ref_top[0..5]

    let filter2 = |a: u8, b: u8| -> u8 { ((a as i32 + b as i32 + 1) >> 1) as u8 };
    let filter3 = |a: u8, b: u8, c: u8| -> u8 {
        ((a as i32 + 2 * b as i32 + c as i32 + 2) >> 2) as u8
    };

    let mut blk = [0u8; 16];
    for y in 0..4i32 {
        for x in 0..4i32 {
            let zvr = 2 * x - y;
            blk[(y * 4 + x) as usize] = if zvr >= 0 {
                // kk = x - (y >> 1): index into top reference (0-based in ref_top offset by 1)
                let kk = x - (y >> 1); // p[kk, -1]
                if zvr % 2 == 0 {
                    // 2-tap: (p[kk-1,-1] + p[kk,-1] + 1) >> 1
                    let a = ref_top[(kk - 1 + 1) as usize]; // kk-1 → index kk
                    let b = ref_top[(kk + 1) as usize];     // kk   → index kk+1
                    filter2(a, b)
                } else {
                    // 3-tap: (p[kk-2,-1] + 2*p[kk-1,-1] + p[kk,-1] + 2) >> 2
                    let a = ref_top[(kk - 2 + 1) as usize]; // kk-2 → index kk-1
                    let b = ref_top[(kk - 1 + 1) as usize]; // kk-1 → index kk
                    let c = ref_top[(kk + 1) as usize];     // kk   → index kk+1
                    filter3(a, b, c)
                }
            } else if zvr == -1 {
                // (p[-1,0] + 2*p[-1,-1] + p[0,-1] + 2) >> 2
                filter3(l[0], tl, t[0])
            } else {
                // zvr < -1: zVR ∈ {-2, -3}  →  y ∈ {2,3} and x < (y-1)/2
                // pred = (p[-1, y-1] + 2*p[-1, y-2] + p[-1, y-3] + 2) >> 2
                // where p[-1,-1] = tl, p[-1,-2] clamps to p[-1,0]
                // p[-1, k] for k >= 0 is l[k]; for k == -1 it is tl
                let get_left = |k: i32| -> u8 {
                    if k < 0 { tl } else { l[k as usize] }
                };
                filter3(get_left(y - 1), get_left(y - 2), get_left(y - 3))
            };
        }
    }
    blk
}

/// Mode 6 Horizontal-Down 4×4 (§8.3.1.2.7).
///
/// Symmetric to mode 5 with x and y transposed, and top ↔ left.
///
/// Let zHD = 2*y - x.
///   zHD even ≥ 0 (0,2,4,6):  pred = (p[-1,y-(x>>1)-1] + p[-1,y-(x>>1)] + 1) >> 1
///   zHD odd  > 0 (1,3,5,7):  pred = (p[-1,y-(x>>1)-2] + 2*p[-1,y-(x>>1)-1] + p[-1,y-(x>>1)] + 2) >> 2
///   zHD == -1:                pred = (p[0,-1] + 2*p[-1,-1] + p[-1,0] + 2) >> 2
///   zHD < -1 (i.e. -2,-3):   pred = (p[x-1,-1] + 2*p[x-2,-1] + p[x-3,-1] + 2) >> 2
fn horiz_down_4x4(t: &[u8; 8], l: &[u8; 4], tl: u8) -> [u8; 16] {
    // ref_left[k] = p[-1, k-1]: ref_left[0]=tl, ref_left[1]=l[0], ..., ref_left[4]=l[3]
    let ref_left: [u8; 5] = [tl, l[0], l[1], l[2], l[3]];

    let filter2 = |a: u8, b: u8| -> u8 { ((a as i32 + b as i32 + 1) >> 1) as u8 };
    let filter3 = |a: u8, b: u8, c: u8| -> u8 {
        ((a as i32 + 2 * b as i32 + c as i32 + 2) >> 2) as u8
    };

    let mut blk = [0u8; 16];
    for y in 0..4i32 {
        for x in 0..4i32 {
            let zhd = 2 * y - x;
            blk[(y * 4 + x) as usize] = if zhd >= 0 {
                let kk = y - (x >> 1); // p[-1, kk]
                if zhd % 2 == 0 {
                    // 2-tap: (p[-1,kk-1] + p[-1,kk] + 1) >> 1
                    let a = ref_left[(kk - 1 + 1) as usize];
                    let b = ref_left[(kk + 1) as usize];
                    filter2(a, b)
                } else {
                    // 3-tap: (p[-1,kk-2] + 2*p[-1,kk-1] + p[-1,kk] + 2) >> 2
                    let a = ref_left[(kk - 2 + 1) as usize];
                    let b = ref_left[(kk - 1 + 1) as usize];
                    let c = ref_left[(kk + 1) as usize];
                    filter3(a, b, c)
                }
            } else if zhd == -1 {
                // (p[0,-1] + 2*p[-1,-1] + p[-1,0] + 2) >> 2
                filter3(t[0], tl, l[0])
            } else {
                // zhd < -1: use top samples
                // pred = (p[x-1,-1] + 2*p[x-2,-1] + p[x-3,-1] + 2) >> 2
                // where p[-1,-1]=tl, p[k,-1]=t[k] for k>=0
                let get_top = |k: i32| -> u8 {
                    if k < 0 { tl } else { t[k as usize] }
                };
                filter3(get_top(x - 1), get_top(x - 2), get_top(x - 3))
            };
        }
    }
    blk
}

/// Mode 7 Vertical-Left 4×4 (§8.3.1.2.8).
///
/// Uses `t[0..8]` (top[0..4] + above-right top[4..8]).
/// The above-right replication for `!have_top_right` is already applied
/// in the caller's `t` array (top[3] replicated into t[4..8]).
///
/// For each (x, y):
///   y ∈ {0, 2}:  pred = (t[x + y/2] + t[x + y/2 + 1] + 1) >> 1
///   y ∈ {1, 3}:  pred = (t[x + y/2] + 2*t[x + y/2 + 1] + t[x + y/2 + 2] + 2) >> 2
fn vert_left_4x4(t: &[u8; 8]) -> [u8; 16] {
    let filter2 = |a: u8, b: u8| -> u8 { ((a as i32 + b as i32 + 1) >> 1) as u8 };
    let filter3 = |a: u8, b: u8, c: u8| -> u8 {
        ((a as i32 + 2 * b as i32 + c as i32 + 2) >> 2) as u8
    };

    let mut blk = [0u8; 16];
    for y in 0..4usize {
        for x in 0..4usize {
            let k = x + y / 2; // index into t
            blk[y * 4 + x] = if y % 2 == 0 {
                // even rows: 2-tap average
                filter2(t[k], t[k + 1])
            } else {
                // odd rows: 3-tap weighted
                filter3(t[k], t[k + 1], t[k + 2])
            };
        }
    }
    blk
}

/// Mode 8 Horizontal-Up 4×4 (§8.3.1.2.9).
///
/// Uses `l[0..4]` (left column) only.
///
/// Let zHU = x + 2*y.
///   zHU == 0, 2, 4:  pred = (l[y + x/2] + l[y + x/2 + 1] + 1) >> 1
///   zHU == 1, 3:     pred = (l[y + x/2] + 2*l[y + x/2 + 1] + l[y + x/2 + 2] + 2) >> 2
///   zHU == 5:        pred = (l[2] + 3*l[3] + 2) >> 2
///   zHU ≥ 6:         pred = l[3]
fn horiz_up_4x4(l: &[u8; 4]) -> [u8; 16] {
    let filter2 = |a: u8, b: u8| -> u8 { ((a as i32 + b as i32 + 1) >> 1) as u8 };
    let filter3 = |a: u8, b: u8, c: u8| -> u8 {
        ((a as i32 + 2 * b as i32 + c as i32 + 2) >> 2) as u8
    };

    let mut blk = [0u8; 16];
    for y in 0..4usize {
        for x in 0..4usize {
            let zhu = x + 2 * y;
            blk[y * 4 + x] = match zhu {
                0 | 2 | 4 => {
                    let k = y + x / 2;
                    filter2(l[k], l[k + 1])
                }
                1 | 3 => {
                    let k = y + x / 2;
                    filter3(l[k], l[k + 1], l[k + 2])
                }
                5 => filter3(l[2], l[3], l[3]), // (l[2] + 3*l[3] + 2) >> 2 = filter(l[2], l[3], l[3])
                _ => l[3], // zhu >= 6
            };
        }
    }
    blk
}

// ─────────────────────────────────────────────────────────────────────────────
// Intra_16x16 luma prediction  (H.264 §8.3.3)
// ─────────────────────────────────────────────────────────────────────────────
//
// Modes:
//   0  Vertical   — copy the 16 top samples down all rows
//   1  Horizontal — copy the 16 left samples across all columns
//   2  DC         — single DC value, average of available neighbors (else 128)
//   3  Plane      — bilinear ramp derived from the top/left arrays + top-left corner
//
// §8.3.3.1: all modes require have_top (mode 0,3) or have_left (mode 1,3);
//           mode 2 works with any combination; mode 3 needs both.

/// Intra_16x16 luma prediction.
///
/// * `mode`      — prediction mode (0..=3; unknowns fall back to DC)
/// * `left`      — 16 left-column samples [p[-1,0]..p[-1,15]], top-to-bottom
/// * `top`       — 16 above-row samples [p[0,-1]..p[15,-1]], left-to-right
/// * `top_left`  — corner sample p[-1,-1]
/// * `have_left` / `have_top` — availability flags
pub fn intra16x16_predict(
    mode: u8,
    left: &[u8; 16],
    top: &[u8; 16],
    top_left: u8,
    have_left: bool,
    have_top: bool,
) -> [u8; 256] {
    match mode {
        // ── Mode 0: Vertical ─────────────────────────────────────────────────
        0 if have_top => {
            let mut blk = [0u8; 256];
            for row in 0..16 {
                blk[row * 16..row * 16 + 16].copy_from_slice(top);
            }
            blk
        }

        // ── Mode 1: Horizontal ───────────────────────────────────────────────
        1 if have_left => {
            let mut blk = [0u8; 256];
            for row in 0..16 {
                let s = left[row];
                for col in 0..16 {
                    blk[row * 16 + col] = s;
                }
            }
            blk
        }

        // ── Mode 2: DC ───────────────────────────────────────────────────────
        2 => {
            let dc = dc16_value(
                if have_left { Some(left) } else { None },
                if have_top { Some(top) } else { None },
            );
            [dc; 256]
        }

        // ── Mode 3: Plane ────────────────────────────────────────────────────
        // §8.3.3.4: requires both top and left (and top-left corner)
        3 if have_top && have_left => plane16x16(top, left, top_left),

        // Fallback to DC for unavailable modes (e.g. mode 3 without neighbors,
        // or any unrecognised mode value)
        _ => {
            let dc = dc16_value(
                if have_left { Some(left) } else { None },
                if have_top { Some(top) } else { None },
            );
            [dc; 256]
        }
    }
}

/// DC value for Intra_16x16.
fn dc16_value(left: Option<&[u8; 16]>, top: Option<&[u8; 16]>) -> u8 {
    match (left, top) {
        (Some(l), Some(t)) => {
            let sum: i32 = l.iter().map(|&x| x as i32).sum::<i32>()
                + t.iter().map(|&x| x as i32).sum::<i32>();
            // (sum + 16) / 32
            ((sum + 16) >> 5) as u8
        }
        (Some(l), None) => {
            let sum: i32 = l.iter().map(|&x| x as i32).sum();
            ((sum + 8) >> 4) as u8
        }
        (None, Some(t)) => {
            let sum: i32 = t.iter().map(|&x| x as i32).sum();
            ((sum + 8) >> 4) as u8
        }
        (None, None) => 128,
    }
}

/// Mode 3 Plane prediction for 16×16 (§8.3.3.4).
///
/// H = Σ_{i=0}^{7} (i+1) * (top[8+i] - top[6-i])
/// V = Σ_{i=0}^{7} (i+1) * (left[8+i] - left[6-i])
/// a = 16 * (top[15] + left[15])
/// b = (5*H + 32) >> 6
/// c = (5*V + 32) >> 6
/// pred[x,y] = clamp((a + b*(x-7) + c*(y-7) + 16) >> 5, 0, 255)
fn plane16x16(top: &[u8; 16], left: &[u8; 16], top_left: u8) -> [u8; 256] {
    // §8.3.3.4 uses p[-1,-1] (top_left) as top[-1] / left[-1] conceptually
    // The standard formula for H references top[-1..15] where top[-1]=top_left.
    // H = Σ_{i=1}^{8} i * (p[i,-1] - p[-i,-1])
    //   where p[8,-1]=top[7], p[-1,-1]=top_left, p[-8,-1]=top_left for i=8 edge
    // Simpler: use the widely-used JM reference formulation:
    //   H = Σ_{i=0}^{6} (i+1)*(top[8+i]-top[6-i])  + 8*(top[15]-top_left)
    //   V = Σ_{i=0}^{6} (i+1)*(left[8+i]-left[6-i]) + 8*(left[15]-top_left)

    let mut h: i32 = 0;
    for i in 0..7i32 {
        h += (i + 1) * (top[(8 + i) as usize] as i32 - top[(6 - i) as usize] as i32);
    }
    h += 8 * (top[15] as i32 - top_left as i32);

    let mut v: i32 = 0;
    for i in 0..7i32 {
        v += (i + 1) * (left[(8 + i) as usize] as i32 - left[(6 - i) as usize] as i32);
    }
    v += 8 * (left[15] as i32 - top_left as i32);

    let a: i32 = 16 * (top[15] as i32 + left[15] as i32);
    let b: i32 = (5 * h + 32) >> 6;
    let c: i32 = (5 * v + 32) >> 6;

    let mut blk = [0u8; 256];
    for y in 0..16i32 {
        for x in 0..16i32 {
            let val = (a + b * (x - 7) + c * (y - 7) + 16) >> 5;
            blk[(y * 16 + x) as usize] = val.clamp(0, 255) as u8;
        }
    }
    blk
}

// ─────────────────────────────────────────────────────────────────────────────
// Reconstruction round-trip  (residual → DCT → quant → dequant → IDCT → add)
// ─────────────────────────────────────────────────────────────────────────────

/// Encode + reconstruct a 4×4 luma block over an intra prediction.
///
/// 1. Compute residual = src − pred  (integer subtraction)
/// 2. Forward DCT:    r      = fdct4x4(residual)
/// 3. Quantise:       levels = quant4x4(r, qp)
/// 4. Dequantise:     dq     = dequant4x4(levels, qp)
/// 5. Inverse DCT:    rec_r  = idct4x4(dq)   (includes >>6 normalisation)
/// 6. Reconstruct:    recon  = clamp(pred + rec_r, 0, 255)
///
/// Returns `(recon, levels)`.  `levels` in zig-zag order
/// (via `crate::h264_transform::ZIGZAG4`) are the symbols consumed by the
/// CAVLC entropy coder.
pub fn encode_reconstruct_4x4(
    src: &[u8; 16],
    pred: &[u8; 16],
    qp: u8,
) -> ([u8; 16], [i32; 16]) {
    // Step 1: residual
    let mut residual = [0i32; 16];
    for i in 0..16 {
        residual[i] = src[i] as i32 - pred[i] as i32;
    }

    // Step 2: forward DCT
    let r = fdct4x4(&residual);

    // Step 3: quantise
    let levels = quant4x4(&r, qp);

    // Step 4: dequantise
    let dq = dequant4x4(&levels, qp);

    // Step 5: inverse DCT (includes >>6 normalisation per spec)
    let rec_r = idct4x4(&dq);

    // Step 6: add prediction + clamp to [0, 255]
    let mut recon = [0u8; 16];
    for i in 0..16 {
        let v = pred[i] as i32 + rec_r[i];
        recon[i] = v.clamp(0, 255) as u8;
    }

    (recon, levels)
}

