    #[test]
    fn intra4x4_vert_right_vertical_structure() {
        // With a strongly rising top row, mode 5 should produce a block that
        // varies more along x than along y (vertical-ish structure).
        let top: [u8; 8] = [10, 50, 100, 150, 150, 150, 150, 150];
        let left: [u8; 4] = [20, 20, 20, 20];
        let blk = intra4x4_predict(5, &left, &top, 15, true, true, false);
        // Column 3 should generally be larger than column 0 across all rows
        let col0_avg: i32 = (0..4).map(|r| blk[r * 4 + 0] as i32).sum::<i32>() / 4;
        let col3_avg: i32 = (0..4).map(|r| blk[r * 4 + 3] as i32).sum::<i32>() / 4;
        assert!(
            col3_avg > col0_avg,
            "mode 5 vertical-right: col3 avg {} should exceed col0 avg {}",
            col3_avg,
            col0_avg
        );
    }

    #[test]
    fn intra4x4_vert_right_hand_worked_sample() {
        // Hand-verify blk[0,0] (x=0, y=0): zVR = 0 (even ≥ 0)
        // kk = 0 - 0 = 0; 2-tap: (ref_top[0] + ref_top[1] + 1) >> 1
        //                       = (tl + t[0] + 1) >> 1
        // With tl=100, t[0]=120: (100 + 120 + 1) >> 1 = 221 >> 1 = 110
        let top: [u8; 8] = [120, 130, 140, 150, 150, 150, 150, 150];
        let left: [u8; 4] = [110, 100, 90, 80];
        let tl = 100u8;
        let blk = intra4x4_predict(5, &left, &top, tl, true, true, false);
        let expected_00 = ((tl as i32 + top[0] as i32 + 1) >> 1) as u8;
        assert_eq!(
            blk[0], expected_00,
            "mode 5 blk[0,0]: expected {}, got {}",
            expected_00, blk[0]
        );
        // blk[1,0] (x=1, y=0): zVR=2 (even), kk=1; (ref_top[1]+ref_top[2]+1)>>1
        //                     = (t[0]+t[1]+1)>>1 = (120+130+1)>>1 = 125
        let expected_01 = ((top[0] as i32 + top[1] as i32 + 1) >> 1) as u8;
        assert_eq!(
            blk[1], expected_01,
            "mode 5 blk[0,1]: expected {}, got {}",
            expected_01, blk[1]
        );
        // blk[1] (y=0, x=1, zVR=2 even, kk=1): verified above
        // blk[4] (y=1, x=0, zVR=-1): (l[0]+2*tl+t[0]+2)>>2
        let expected_10 = ((left[0] as i32 + 2 * tl as i32 + top[0] as i32 + 2) >> 2) as u8;
        assert_eq!(
            blk[4], expected_10,
            "mode 5 blk[1,0] (zVR=-1): expected {}, got {}",
            expected_10, blk[4]
        );
    }

